import { Component } from '@angular/core';
import { HttpClient } from '@angular/common/http';

@Component({
  selector: 'app-dotnet-integration',
  template: `
    <button (click)="loadData()">Load policies</button>
    <div *ngIf="policies">{{ policies | json }}</div>
  `
})
export class DotnetIntegrationComponent {
  policies: any;

  constructor(private http: HttpClient) {}

  loadData() {
    this.http.get('/api/policies').subscribe({
      next: (result) => (this.policies = result),
      error: (error) => console.error('API error', error),
    });
  }
}

